import { useState } from "react";

const FORMSPREE = "https://formspree.io/f/mvzynazl";
const WHATSAPP  = "573183926718";

const IMG_BOGOTA    = "data:image/png;base64,";
const IMG_CLINICA   = "data:image/png;base64,";
const IMG_MAMA_HIJO = "data:image/png;base64,";
const IMG_VIVI      = "data:image/png;base64,";

const TARIFAS = {
  DES: { "0-4": 678937, "5-14 H": 410956, "5-14 M": 410956, "15+ H": 715656, "15+ M": 647757 },
  DE:  { "0-4": 485921, "5-14 H": 294152, "5-14 M": 294152, "15+ H": 512246, "15+ M": 541430 },
  ZE:  { "0-4": 355772, "5-14 H": 263760, "5-14 M": 263760, "15+ H": 375014, "15+ M": 484272 },
};

const desc15 = (n) => Math.round(n * 0.85);
const fmt    = (n) => "$" + n.toLocaleString("es-CO");

const C = {
  bg:"#F7F8FC", white:"#FFFFFF", navy:"#0F1F3D",
  blue:"#1A5CFF", blueLight:"#EEF3FF",
  purple:"#6C3BFF", purpleLight:"#F0EBFF",
  gray:"#7A869A", grayLight:"#E8ECF4",
};

const PROGRESS = {intro:0,q1:10,inter1:20,q2:30,q2b:40,inter2:50,q3:60,inter3:70,q4:82,q5:96,blocked:15};
const STEP_LBL = {q1:"1/6",q2:"2/6",q2b:"3/6",q3:"4/6",q4:"5/6",q5:"6/6"};

export default function ViviQuiz() {
  const [history, setHistory] = useState(["intro"]);
  const [vals, setVals]       = useState({});
  const [habeas, setHabeas]   = useState(false);
  const [name, setName]       = useState("");
  const [phone, setPhone]     = useState("");
  const [sending, setSending] = useState(false);
  const [sent, setSent]       = useState(false);
  const [animKey, setAnimKey] = useState(0);

  const cur  = history[history.length - 1];
  const go   = (s) => { setAnimKey(k=>k+1); setHistory(h=>[...h,s]); };
  const back = () => { if(history.length>1){ setAnimKey(k=>k+1); setHistory(h=>h.slice(0,-1)); }};
  const sel  = (k,v) => setVals(p=>({...p,[k]:v}));

  const getTKey = () => {
    const e=vals.edad, g=vals.genero;
    if(!e||!g) return null;
    if(e==="0-4")  return "0-4";
    if(e==="5-14") return g==="H"?"5-14 H":"5-14 M";
    if(e==="15+")  return g==="H"?"15+ H":"15+ M";
    return null;
  };

  const getPrices = () => {
    const k=getTKey();
    if(!k) return null;
    return {
      DES:{ base:TARIFAS.DES[k], conv:desc15(TARIFAS.DES[k]) },
      DE: { base:TARIFAS.DE[k],  conv:desc15(TARIFAS.DE[k])  },
      ZE: { base:TARIFAS.ZE[k],  conv:desc15(TARIFAS.ZE[k])  },
    };
  };

  const disabled = () => {
    if(cur==="q1")  return !vals.ciudad;
    if(cur==="q2")  return !vals.edad;
    if(cur==="q2b") return !vals.genero;
    if(cur==="q3")  return !vals.prioridad;
    if(cur==="q4")  return !vals.plan;
    if(cur==="q5"||cur==="blocked") return !habeas||!name||!phone;
    return false;
  };

  const submitAndWA = async () => {
    setSending(true);
    const pr=getPrices();
    const planKey=vals.plan==="Diamante Élite Superior"?"DES":vals.plan==="Diamante Élite"?"DE":"ZE";
    try {
      await fetch(FORMSPREE,{
        method:"POST",
        headers:{"Content-Type":"application/json","Accept":"application/json"},
        body:JSON.stringify({
          nombre:name, whatsapp:phone,
          ciudad:vals.ciudad==="bogota"?"Bogotá":"Otra ciudad",
          edad:vals.edad, genero:vals.genero==="H"?"Masculino":"Femenino",
          prioridad:vals.prioridad, plan:vals.plan,
          tarifa_descuento:pr?fmt(pr[planKey].conv):"—",
          fuente:"Quiz Coberturas Salud - Viviana Perdomo",
        }),
      });
    } catch(e){ console.error(e); }
    setSending(false); setSent(true);
    const generoLabel = vals.genero==="H"?"Masculino":"Femenino";
    const edadLabel = vals.edad==="0-4"?"Menor de 5 años":vals.edad==="5-14"?"Entre 5 y 14 años":"Mayor de 14 años";
    const msg=encodeURIComponent(`Hola Viviana! 👋 Completé el diagnóstico de cobertura de salud.\n\n👤 *${name}*\n📋 Plan de interés: *${vals.plan||"—"}*\n🧒 Edad del menor: *${edadLabel}*\n🧬 Género: *${generoLabel}*\n\n¿Podemos hablar para validar mi cobertura?`);
    setTimeout(()=>window.open(`https://wa.me/${WHATSAPP}?text=${msg}`,"_blank"),300);
  };

  const next = () => {
    if(cur==="intro")  { go("q1"); return; }
    if(cur==="q1")     { go(vals.ciudad==="nacional"?"blocked":"inter1"); return; }
    if(cur==="inter1") { go("q2"); return; }
    if(cur==="q2")     { go("q2b"); return; }
    if(cur==="q2b")    { go("inter2"); return; }
    if(cur==="inter2") { go("q3"); return; }
    if(cur==="q3")     { go("inter3"); return; }
    if(cur==="inter3") { go("q4"); return; }
    if(cur==="q4")     { go("q5"); return; }
    if(cur==="q5"||cur==="blocked") { submitAndWA(); }
  };

  const isWA=cur==="q5"||cur==="blocked";
  const showHdr=cur!=="intro";
  const pct=PROGRESS[cur]||0;
  const p=getPrices();

  const card=(on,ac=C.blue)=>({
    background:on?(ac===C.purple?C.purpleLight:C.blueLight):C.white,
    border:`1.5px solid ${on?ac:C.grayLight}`,
    borderRadius:16,padding:"15px 18px",
    display:"flex",alignItems:"center",gap:14,
    cursor:"pointer",marginBottom:10,
    boxShadow:on?`0 0 0 3px ${ac}22`:"0 2px 8px rgba(15,31,61,0.06)",
    transition:"all 0.18s",
  });
  const chk=(on,ac=C.blue)=>({
    width:24,height:24,borderRadius:"50%",
    border:`2px solid ${on?ac:C.grayLight}`,
    background:on?ac:"transparent",
    display:"flex",alignItems:"center",justifyContent:"center",
    flexShrink:0,color:"#fff",fontSize:12,fontWeight:800,
  });
  const bdg=(ac=C.purple)=>({
    display:"inline-flex",alignItems:"center",gap:5,
    background:ac===C.purple?C.purpleLight:C.blueLight,
    color:ac,borderRadius:100,padding:"5px 13px",
    fontSize:12,fontWeight:700,marginBottom:14,
  });
  const hl={
    background:"linear-gradient(135deg,#EEF3FF,#F0EBFF)",
    border:"1px solid rgba(108,59,255,0.15)",
    borderRadius:14,padding:"14px 16px",
    fontSize:14,lineHeight:1.65,color:C.navy,marginBottom:14,
  };
  const inp={
    width:"100%",background:C.white,
    border:`1.5px solid ${C.grayLight}`,
    borderRadius:14,padding:"14px 16px",
    color:C.navy,fontSize:15,fontFamily:"inherit",
    marginBottom:10,display:"block",outline:"none",
  };
  const note={fontSize:11,color:C.gray,lineHeight:1.5,marginTop:4,fontStyle:"italic"};

  const HabeasRow=()=>(
    <div onClick={()=>setHabeas(h=>!h)} style={{display:"flex",alignItems:"flex-start",gap:12,background:C.white,border:`1px solid ${C.grayLight}`,borderRadius:14,padding:"14px 16px",marginBottom:6,cursor:"pointer"}}>
      <div style={{width:22,height:22,borderRadius:6,border:`2px solid ${habeas?C.purple:C.grayLight}`,background:habeas?C.purple:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,color:"#fff",fontSize:13,fontWeight:800,marginTop:1}}>{habeas?"✓":""}</div>
      <p style={{fontSize:12,color:C.gray,lineHeight:1.55}}>Autorizo el tratamiento de mis datos personales para recibir asesoría de <strong style={{color:C.navy}}>Viviana Perdomo</strong>, especialista en coberturas de salud (Ley 1581 de 2012).</p>
    </div>
  );

  if(sent) return (
    <div style={{fontFamily:"'Sora',system-ui,sans-serif",background:C.bg,minHeight:"100vh",maxWidth:430,margin:"0 auto",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"32px 24px",textAlign:"center"}}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Sora:wght@400;600;700;800&display=swap');`}</style>
      <div style={{width:80,height:80,borderRadius:"50%",background:`linear-gradient(135deg,${C.blue},${C.purple})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:34,color:"#fff",fontWeight:800,marginBottom:16,boxShadow:`0 8px 28px rgba(108,59,255,0.35)`}}>✓</div>
      <h2 style={{fontSize:22,fontWeight:800,color:C.navy,marginBottom:8}}>¡Todo listo, {name.split(" ")[0]}!</h2>
      <p style={{fontSize:14,color:C.gray,lineHeight:1.6,marginBottom:16}}>Tu diagnóstico fue registrado. Abriendo WhatsApp para conectarte con Viviana...</p>
      <img src={IMG_VIVI} alt="Viviana" style={{width:120,height:120,borderRadius:"50%",objectFit:"cover",objectPosition:"top",border:`3px solid ${C.purple}`,marginBottom:16}}/>
      <div style={{background:C.white,border:`1px solid ${C.grayLight}`,borderRadius:16,padding:"16px",width:"100%"}}>
        {[["Ciudad",vals.ciudad==="bogota"?"Bogotá D.C.":"Otra ciudad"],["Edad",vals.edad],["Género",vals.genero==="H"?"Masculino":"Femenino"],["Plan",vals.plan||"—"]].map(([k,v])=>(
          <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:`1px solid ${C.grayLight}`,fontSize:13}}>
            <span style={{color:C.gray}}>{k}</span><span style={{fontWeight:600,color:C.navy}}>{v}</span>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div style={{fontFamily:"'Sora',system-ui,sans-serif",background:C.bg,minHeight:"100vh",maxWidth:430,margin:"0 auto",display:"flex",flexDirection:"column",position:"relative"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@400;500;600;700;800&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        input::placeholder{color:#A0AABF;}
        input:focus{border-color:#1A5CFF!important;outline:none;}
        @keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
        .su{animation:fadeUp 0.32s cubic-bezier(0.22,1,0.36,1) forwards}
      `}</style>

      {/* HEADER */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"16px 20px 10px",background:C.white,borderBottom:`1px solid ${C.grayLight}`,position:"sticky",top:0,zIndex:50}}>
        {showHdr
          ? <button onClick={back} style={{width:36,height:36,borderRadius:"50%",border:`1.5px solid ${C.grayLight}`,background:C.white,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,color:C.navy}}>←</button>
          : <div style={{width:36}}/>}
        <div style={{textAlign:"center"}}>
          <div style={{fontSize:16,fontWeight:800}}>
            <span style={{color:C.blue}}>Viviana</span><span style={{color:C.purple}}> Perdomo</span>
          </div>
          <div style={{fontSize:10,color:C.gray,marginTop:1}}>Especialista en Coberturas de Salud</div>
        </div>
        <div style={{fontSize:12,fontWeight:700,color:C.blue,minWidth:36,textAlign:"right"}}>{STEP_LBL[cur]||""}</div>
      </div>

      {showHdr && (
        <div style={{height:3,background:C.grayLight}}>
          <div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${C.blue},${C.purple})`,transition:"width 0.5s ease",borderRadius:10}}/>
        </div>
      )}

      <div key={animKey} className="su" style={{flex:1,overflowY:"auto",paddingBottom:110}}>

        {/* INTRO */}
        {cur==="intro" && (
          <div>
            <div style={{background:`linear-gradient(145deg,${C.navy},#1A2E5A)`,padding:"40px 24px 32px",textAlign:"center",position:"relative",overflow:"hidden"}}>
              <div style={{position:"absolute",top:-40,right:-40,width:180,height:180,borderRadius:"50%",background:"rgba(108,59,255,0.25)",filter:"blur(50px)"}}/>
              <div style={{position:"absolute",bottom:-20,left:-30,width:120,height:120,borderRadius:"50%",background:"rgba(26,92,255,0.3)",filter:"blur(30px)"}}/>
              <div style={{position:"relative",zIndex:2}}>
                <div style={{fontSize:72,marginBottom:16}}>🏥</div>
                <div style={{display:"inline-flex",alignItems:"center",gap:6,background:"rgba(255,255,255,0.12)",border:"1px solid rgba(255,255,255,0.2)",borderRadius:100,padding:"5px 14px",fontSize:12,fontWeight:600,color:"#fff",marginBottom:18}}>🎯 Diagnóstico Gratuito · 2 min</div>
                <h1 style={{fontSize:26,fontWeight:800,color:"#fff",lineHeight:1.2,marginBottom:12}}>
                  ¿Tu familia tiene la cobertura de salud{" "}
                  <span style={{background:"linear-gradient(135deg,#7EB8FF,#B49DFF)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>que realmente merece?</span>
                </h1>
                <p style={{fontSize:14,color:"rgba(255,255,255,0.7)",lineHeight:1.6}}>Responde 6 preguntas y descubre si calificas para el <strong style={{color:"#B49DFF"}}>descuento especial</strong> en atención médica VIP.</p>
              </div>
            </div>
            <div style={{padding:"20px 20px 0"}}>
              <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:18}}>
                {["🏥 Clínicas élite","⚡ Sin esperas","💎 15% OFF","🩺 Libre elección"].map(pill=>(
                  <div key={pill} style={{background:C.white,border:`1px solid ${C.grayLight}`,borderRadius:100,padding:"6px 13px",fontSize:12,fontWeight:500,color:C.navy,boxShadow:"0 1px 4px rgba(15,31,61,0.07)"}}>{pill}</div>
                ))}
              </div>
              <div style={{background:C.white,border:`1px solid ${C.grayLight}`,borderRadius:16,padding:"14px",display:"flex",alignItems:"center",gap:12,boxShadow:"0 2px 10px rgba(15,31,61,0.06)"}}>
                <img src={IMG_VIVI} alt="Viviana" style={{width:48,height:48,borderRadius:"50%",objectFit:"cover",objectPosition:"top",border:`2px solid ${C.purple}`,flexShrink:0}}/>
                <div style={{flex:1}}>
                  <div style={{fontSize:13,fontWeight:700,color:C.navy}}>Viviana Perdomo</div>
                  <div style={{fontSize:12,color:C.gray}}>Especialista en Coberturas de Salud</div>
                </div>
                <div style={{background:C.purpleLight,color:C.purple,fontSize:11,fontWeight:700,padding:"4px 10px",borderRadius:100,flexShrink:0}}>Verificada ✓</div>
              </div>
            </div>
          </div>
        )}

        {/* Q1 CIUDAD */}
        {cur==="q1" && (
          <div style={{padding:"24px 20px"}}>
            <div style={bdg(C.blue)}>📍 Pregunta 1 de 6</div>
            <h2 style={{fontSize:22,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:8}}>¿En qué ciudad resides actualmente?</h2>
            <p style={{fontSize:14,color:C.gray,marginBottom:16,lineHeight:1.5}}>Las redes de clínicas varían según tu ciudad.</p>
            <div style={{borderRadius:16,overflow:"hidden",marginBottom:18,border:`1px solid ${C.grayLight}`}}>
              <img src={IMG_BOGOTA} alt="Bogotá" style={{width:"100%",height:155,objectFit:"cover",objectPosition:"center 55%",display:"block"}}/>
            </div>
            {[
              {v:"bogota",   icon:"📍",t:"Bogotá D.C.",              s:"Acceso a red de clínicas VIP"},
              {v:"nacional", icon:"🇨🇴",t:"Otra ciudad de Colombia", s:"Cobertura nacional disponible"},
            ].map(o=>(
              <div key={o.v} style={card(vals.ciudad===o.v)} onClick={()=>sel("ciudad",o.v)}>
                <div style={{fontSize:26,width:44,height:44,background:vals.ciudad===o.v?C.blueLight:C.bg,borderRadius:12,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{o.icon}</div>
                <div style={{flex:1}}>
                  <div style={{fontSize:15,fontWeight:600,color:C.navy}}>{o.t}</div>
                  <div style={{fontSize:12,color:vals.ciudad===o.v?C.blue:C.gray,marginTop:2}}>{o.s}</div>
                </div>
                <div style={chk(vals.ciudad===o.v)}>{vals.ciudad===o.v?"✓":""}</div>
              </div>
            ))}
          </div>
        )}

        {/* INTER 1 */}
        {cur==="inter1" && (
          <div style={{padding:"24px 20px"}}>
            <div style={{background:`linear-gradient(135deg,${C.navy},#1A2E5A)`,borderRadius:20,padding:"22px 20px",textAlign:"center",marginBottom:20,position:"relative",overflow:"hidden"}}>
              <div style={{position:"absolute",top:-20,right:-20,width:100,height:100,borderRadius:"50%",background:"rgba(108,59,255,0.3)",filter:"blur(25px)"}}/>
              <div style={{fontSize:52,marginBottom:8}}>😰</div>
              <div style={{display:"inline-flex",alignItems:"center",gap:5,background:"rgba(255,100,100,0.2)",border:"1px solid rgba(255,100,100,0.3)",color:"#FF8080",borderRadius:100,padding:"4px 12px",fontSize:11,fontWeight:700,marginBottom:10}}>🚨 DATO URGENTE</div>
              <p style={{color:"#fff",fontSize:14,fontWeight:600,lineHeight:1.4}}>En Bogotá, esperar en urgencias con un Triage 3 puede tomar <span style={{color:"#FF8080"}}>más de 4 horas</span></p>
            </div>
            <div style={hl}>Para una mamá a las <strong>2:00 a.m.</strong> con un niño con fiebre, cada minuto importa. El acceso directo a clínicas de alto nivel <strong style={{color:C.purple}}>elimina esa incertidumbre</strong>.</div>
            <div style={{display:"flex",justifyContent:"space-around",background:C.white,border:`1px solid ${C.grayLight}`,borderRadius:16,padding:"16px 8px",boxShadow:"0 2px 12px rgba(15,31,61,0.06)"}}>
              {[["4h+","Espera urgencias\nsistema tradicional"],["~15m","Atención en\nclínicas élite"],["24/7","Disponibilidad\npermanente"]].map(([n,l])=>(
                <div key={n} style={{textAlign:"center"}}>
                  <span style={{fontSize:22,fontWeight:800,color:C.blue,display:"block"}}>{n}</span>
                  <span style={{fontSize:10,color:C.gray,lineHeight:1.3,display:"block",marginTop:2}}>{l.split("\n").map((t,i)=><span key={i}>{t}{i===0&&<br/>}</span>)}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Q2 EDAD */}
        {cur==="q2" && (
          <div style={{padding:"24px 20px"}}>
            <div style={bdg(C.purple)}>🧸 Pregunta 2 de 6</div>
            <h2 style={{fontSize:22,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:8}}>¿Qué edad tiene el menor que deseas proteger?</h2>
            <p style={{fontSize:14,color:C.gray,marginBottom:20,lineHeight:1.5}}>La edad determina la tarifa de convenio disponible.</p>
            {[
              {v:"0-4", icon:"👶",t:"Menor de 5 años",   s:"Coberturas desde el nacimiento"},
              {v:"5-14",icon:"🧸",t:"Entre 5 y 14 años", s:"✨ Tarifa de Convenio Especial"},
              {v:"15+", icon:"🧑",t:"Mayor de 14 años",  s:"Planes para jóvenes y adultos"},
            ].map(o=>(
              <div key={o.v} style={card(vals.edad===o.v,C.purple)} onClick={()=>sel("edad",o.v)}>
                <div style={{fontSize:28,width:46,height:46,background:vals.edad===o.v?C.purpleLight:C.bg,borderRadius:12,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{o.icon}</div>
                <div style={{flex:1}}>
                  <div style={{fontSize:15,fontWeight:600,color:C.navy}}>{o.t}</div>
                  <div style={{fontSize:12,color:vals.edad===o.v?C.purple:C.gray,marginTop:2}}>{o.s}</div>
                </div>
                <div style={chk(vals.edad===o.v,C.purple)}>{vals.edad===o.v?"✓":""}</div>
              </div>
            ))}
          </div>
        )}

        {/* Q2B GÉNERO */}
        {cur==="q2b" && (
          <div style={{padding:"24px 20px"}}>
            <div style={bdg(C.blue)}>🧬 Pregunta 3 de 6</div>
            <h2 style={{fontSize:22,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:8}}>¿El menor es niño o niña?</h2>
            <p style={{fontSize:14,color:C.gray,marginBottom:20,lineHeight:1.5}}>Esto nos permite calcular la tarifa exacta para su perfil.</p>
            {[
              {v:"H",icon:"👦",t:"Niño (Masculino)"},
              {v:"M",icon:"👧",t:"Niña (Femenino)"},
            ].map(o=>(
              <div key={o.v} style={card(vals.genero===o.v)} onClick={()=>sel("genero",o.v)}>
                <div style={{fontSize:36,width:54,height:54,background:vals.genero===o.v?C.blueLight:C.bg,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{o.icon}</div>
                <div style={{flex:1}}><div style={{fontSize:16,fontWeight:600,color:C.navy}}>{o.t}</div></div>
                <div style={chk(vals.genero===o.v)}>{vals.genero===o.v?"✓":""}</div>
              </div>
            ))}
          </div>
        )}

        {/* INTER 2 */}
        {cur==="inter2" && (
          <div style={{padding:"24px 20px"}}>
            <div style={{background:`linear-gradient(135deg,${C.purpleLight},${C.blueLight})`,borderRadius:20,padding:"24px 20px",textAlign:"center",marginBottom:18,border:"1px solid rgba(108,59,255,0.15)"}}>
              <div style={{fontSize:56,marginBottom:10}}>💡</div>
              <div style={bdg(C.purple)}>{vals.edad==="5-14"?"✨ Descuento de convenio activado":"✅ Plan disponible para ti"}</div>
              <p style={{fontSize:14,fontWeight:600,color:C.navy,lineHeight:1.5}}>
                {vals.edad==="5-14"
                  ? <>El rango 5–14 activa un <span style={{color:C.purple}}>descuento del 15%*</span> sobre la tarifa plena individual.</>
                  : <>Tu familia merece <span style={{color:C.blue}}>la mejor cobertura</span>. El descuento aplica en todos los rangos.</>}
              </p>
              {vals.edad==="5-14"&&<p style={{fontSize:11,color:C.purple,marginTop:8,fontStyle:"italic"}}>*Frente a tarifa plena individual. Aplica condiciones.</p>}
            </div>
            <div style={{display:"flex",justifyContent:"space-around",background:C.white,border:`1px solid ${C.grayLight}`,borderRadius:16,padding:"16px 8px",marginBottom:12,boxShadow:"0 2px 12px rgba(15,31,61,0.06)"}}>
              {[["15%*","Descuento\nde convenio"],["100%","Cobertura\nhospitalización"],["4","Clínicas\nVIP Bogotá"]].map(([n,l])=>(
                <div key={n} style={{textAlign:"center"}}>
                  <span style={{fontSize:22,fontWeight:800,color:C.purple,display:"block"}}>{n}</span>
                  <span style={{fontSize:10,color:C.gray,lineHeight:1.3,display:"block",marginTop:2}}>{l.split("\n").map((t,i)=><span key={i}>{t}{i===0&&<br/>}</span>)}</span>
                </div>
              ))}
            </div>
            <p style={note}>*Frente a tarifa plena individual. Tarifas 2026 incluyen IVA del 5%.</p>
          </div>
        )}

        {/* Q3 PRIORIDAD */}
        {cur==="q3" && (
          <div style={{padding:"24px 20px"}}>
            <div style={bdg(C.blue)}>🏥 Pregunta 4 de 6</div>
            <h2 style={{fontSize:22,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:8}}>Ante una urgencia nocturna, ¿qué valoras más?</h2>
            <p style={{fontSize:14,color:C.gray,marginBottom:14,lineHeight:1.5}}>Esto nos ayuda a encontrar el plan ideal para tu familia.</p>
            <div style={{borderRadius:16,overflow:"hidden",marginBottom:16,border:`1px solid ${C.grayLight}`}}>
              <img src={IMG_CLINICA} alt="Clínica VIP" style={{width:"100%",height:145,objectFit:"cover",objectPosition:"center 25%",display:"block"}}/>
            </div>
            {[
              {v:"vip",      icon:"🏥",t:"Atención inmediata en clínicas de alto nivel",     s:"Country · Santa Fe · La Mujer · Los Nogales"},
              {v:"flexible", icon:"💛",t:"Cobertura flexible con acompañamiento permanente", s:"Amplia red a nivel nacional"},
            ].map(o=>(
              <div key={o.v} style={card(vals.prioridad===o.v)} onClick={()=>sel("prioridad",o.v)}>
                <div style={{fontSize:26,width:44,height:44,background:vals.prioridad===o.v?C.blueLight:C.bg,borderRadius:12,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{o.icon}</div>
                <div style={{flex:1}}>
                  <div style={{fontSize:14,fontWeight:600,color:C.navy,lineHeight:1.35}}>{o.t}</div>
                  <div style={{fontSize:12,color:vals.prioridad===o.v?C.blue:C.gray,marginTop:3}}>{o.s}</div>
                </div>
                <div style={chk(vals.prioridad===o.v)}>{vals.prioridad===o.v?"✓":""}</div>
              </div>
            ))}
          </div>
        )}

        {/* INTER 3 */}
        {cur==="inter3" && (
          <div style={{padding:"24px 20px"}}>
            <div style={{textAlign:"center",marginBottom:18}}>
              <img src={IMG_VIVI} alt="Viviana" style={{width:88,height:88,borderRadius:"50%",objectFit:"cover",objectPosition:"top",border:`3px solid ${C.purple}`,boxShadow:`0 8px 24px rgba(108,59,255,0.3)`,marginBottom:10}}/>
              <div style={{color:"#F5C842",fontSize:16,letterSpacing:3,marginBottom:8}}>★★★★★</div>
              <div style={bdg(C.purple)}>🛡️ Tu tranquilidad está diseñada</div>
            </div>
            <h2 style={{fontSize:20,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:10}}>
              {vals.prioridad==="vip"?"Acceso directo a la red de clínicas élite":"Acompañamiento permanente en todo momento"}
            </h2>
            <p style={{fontSize:14,color:C.gray,lineHeight:1.6,marginBottom:14}}>
              {vals.prioridad==="vip"
                ? <><strong style={{color:C.navy}}>Tú eliges el especialista y la clínica</strong> dentro de la red VIP. Cobertura en hospitalización y cirugía al 100%.</>
                : <>Amplia red nacional con <strong style={{color:C.navy}}>cobertura completa</strong> y asesoría personalizada en cada paso.</>}
            </p>
            <div style={{...hl,borderLeft:`4px solid ${C.purple}`}}>
              <div style={{fontSize:13,color:C.gray,fontStyle:"italic",lineHeight:1.6,marginBottom:6}}>"La noche que mi hijo tuvo fiebre de 40°, llamé y en menos de 15 minutos estaba siendo atendido en Clínica Country. Eso no tiene precio."</div>
              <div style={{fontSize:12,color:C.gray,fontWeight:600}}>— Mamá afiliada, Bogotá ✓</div>
            </div>
          </div>
        )}

        {/* Q4 PLANES */}
        {cur==="q4" && (
          <div style={{padding:"24px 20px"}}>
            <div style={bdg(C.purple)}>💎 Pregunta 5 de 6</div>
            <h2 style={{fontSize:22,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:4}}>Selecciona el plan para tu familia</h2>
            <p style={{fontSize:13,color:C.gray,marginBottom:16,lineHeight:1.5}}>Elige el nivel de cobertura que mejor se adapte a tu presupuesto.</p>

            {/* DES */}
            {(()=>{
              const s=vals.plan==="Diamante Élite Superior";
              return(
                <div onClick={()=>sel("plan","Diamante Élite Superior")} style={{background:s?C.purpleLight:C.white,border:`1.5px solid ${s?C.purple:"rgba(108,59,255,0.25)"}`,borderRadius:18,padding:"16px",marginBottom:10,cursor:"pointer",boxShadow:s?`0 0 0 3px ${C.purple}22`:"0 2px 10px rgba(15,31,61,0.06)",position:"relative",transition:"all 0.18s"}}>
                  <div style={{position:"absolute",top:12,right:12,background:`linear-gradient(135deg,${C.purple},${C.blue})`,color:"#fff",fontSize:9,fontWeight:800,letterSpacing:1,padding:"3px 9px",borderRadius:100}}>⭐ PREMIUM</div>
                  <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
                    <span style={{fontSize:22}}>💎</span>
                    <div>
                      <div style={{fontSize:14,fontWeight:700,color:C.navy}}>Plan Diamante Élite Superior</div>
                      <div style={{fontSize:11,color:C.gray}}>Cobertura VIP Total</div>
                    </div>
                  </div>
                  <div style={{fontSize:11,color:C.navy,background:s?C.purpleLight:"#F7F8FC",borderRadius:8,padding:"6px 10px",marginBottom:10,lineHeight:1.5}}>✅ Urgencias · Libre elección de especialista · Hospitalización suite* · Cobertura nacional</div>
                  <div style={{display:"flex",alignItems:"baseline",gap:4}}>
                    <span style={{fontSize:13,color:C.gray}}>Desde</span>
                    <span style={{fontSize:26,fontWeight:800,color:C.purple}}>$350.000</span>
                    <span style={{fontSize:12,color:C.gray}}>COP/mes*</span>
                  </div>
                  <p style={note}>*Suite sujeta a disponibilidad</p>
                </div>
              );
            })()}

            {/* DE */}
            {(()=>{
              const s=vals.plan==="Zafiro Élite Nacional";
              return(
                <div onClick={()=>sel("plan","Zafiro Élite Nacional")} style={{background:s?C.blueLight:C.white,border:`1.5px solid ${s?C.blue:C.grayLight}`,borderRadius:18,padding:"16px",marginBottom:10,cursor:"pointer",boxShadow:s?`0 0 0 3px ${C.blue}22`:"0 2px 10px rgba(15,31,61,0.06)",transition:"all 0.18s"}}>
                  <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
                    <span style={{fontSize:22}}>💙</span>
                    <div>
                      <div style={{fontSize:14,fontWeight:700,color:C.navy}}>Plan Zafiro Élite Nacional</div>
                      <div style={{fontSize:11,color:C.gray}}>Respaldo en todo el país</div>
                    </div>
                  </div>
                  <div style={{fontSize:11,color:C.navy,background:s?C.blueLight:"#F7F8FC",borderRadius:8,padding:"6px 10px",marginBottom:10,lineHeight:1.5}}>✅ Urgencias · Citas · Especialistas · Hospitalización · Cobertura nacional</div>
                  <div style={{display:"flex",alignItems:"baseline",gap:4}}>
                    <span style={{fontSize:13,color:C.gray}}>Desde</span>
                    <span style={{fontSize:26,fontWeight:800,color:C.blue}}>$250.000</span>
                    <span style={{fontSize:12,color:C.gray}}>COP/mes*</span>
                  </div>
                </div>
              );
            })()}

            {/* ZE */}
            {(()=>{
              const s=vals.plan==="Zafiro Exclusivo Bogotá";
              return(
                <div onClick={()=>sel("plan","Zafiro Exclusivo Bogotá")} style={{background:s?C.blueLight:C.white,border:`1.5px solid ${s?C.blue:C.grayLight}`,borderRadius:18,padding:"16px",marginBottom:10,cursor:"pointer",boxShadow:s?`0 0 0 3px ${C.blue}22`:"0 2px 10px rgba(15,31,61,0.06)",transition:"all 0.18s"}}>
                  <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
                    <span style={{fontSize:22}}>🏢</span>
                    <div>
                      <div style={{fontSize:14,fontWeight:700,color:C.navy}}>Plan Zafiro Exclusivo Bogotá</div>
                      <div style={{fontSize:11,color:C.gray}}>Cobertura local preferencial</div>
                    </div>
                  </div>
                  <div style={{fontSize:11,color:C.navy,background:s?C.blueLight:"#F7F8FC",borderRadius:8,padding:"6px 10px",marginBottom:10,lineHeight:1.5}}>✅ Urgencias · Citas · Especialistas · Hospitalización · <span style={{color:"#C04000",fontWeight:700}}>📍 Solo Bogotá</span></div>
                  <div style={{display:"flex",alignItems:"baseline",gap:4}}>
                    <span style={{fontSize:13,color:C.gray}}>Desde</span>
                    <span style={{fontSize:26,fontWeight:800,color:C.blue}}>$220.000</span>
                    <span style={{fontSize:12,color:C.gray}}>COP/mes*</span>
                  </div>
                </div>
              );
            })()}

            <p style={{fontSize:11,color:C.gray,lineHeight:1.6,marginTop:8,fontStyle:"italic",padding:"10px 12px",background:"#F0F2F8",borderRadius:10}}>*Tarifas de convenio comercial vigentes. Sujetas a variaciones por edad y políticas de suscripción.</p>
          </div>
        )}

        {/* Q5 CIERRE */}
        {cur==="q5" && (
          <div style={{padding:"24px 20px"}}>
            <div style={{textAlign:"center",marginBottom:20}}>
              <div style={{width:70,height:70,borderRadius:"50%",background:`linear-gradient(135deg,${C.blue},${C.purple})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,color:"#fff",fontWeight:800,margin:"0 auto 14px",boxShadow:`0 8px 28px rgba(108,59,255,0.35)`}}>✓</div>
              <div style={bdg(C.purple)}>🎉 ¡Perfil verificado!</div>
              <h2 style={{fontSize:20,fontWeight:800,color:C.navy,lineHeight:1.25,marginBottom:8}}>Calificas para tarifa de convenio especial</h2>
              <p style={{fontSize:14,color:C.gray,lineHeight:1.5}}>Déjame tus datos y te envío tu cotización exacta en menos de 24h.</p>
            </div>
            <input style={inp} type="text"  placeholder="Tu nombre completo"              value={name}  onChange={e=>setName(e.target.value)}/>
            <input style={inp} type="tel"   placeholder="Tu WhatsApp (ej: 311 234 5678)"  value={phone} onChange={e=>setPhone(e.target.value)}/>
            <HabeasRow/>
            <p style={note}>Al continuar serás redirigida a WhatsApp para confirmar tu asesoría personalizada.</p>
          </div>
        )}

        {/* BLOCKED */}
        {cur==="blocked" && (
          <div style={{padding:"32px 20px",textAlign:"center"}}>
            <div style={{fontSize:56,marginBottom:16}}>🇨🇴</div>
            <h2 style={{fontSize:20,fontWeight:800,color:C.navy,marginBottom:10}}>¡Tenemos cobertura para ti!</h2>
            <p style={{fontSize:14,color:C.gray,lineHeight:1.6,marginBottom:18}}>Contamos con planes de cobertura nacional con excelente red en tu ciudad.</p>
            <div style={{...hl,textAlign:"left",marginBottom:18}}>Déjame tus datos y te contacto con la opción perfecta. <strong style={{color:C.purple}}>El descuento aplica de todas formas.</strong></div>
            <input style={inp} type="text" placeholder="Tu nombre"    value={name}  onChange={e=>setName(e.target.value)}/>
            <input style={inp} type="tel"  placeholder="Tu WhatsApp"  value={phone} onChange={e=>setPhone(e.target.value)}/>
            <HabeasRow/>
          </div>
        )}

      </div>

      {/* CTA */}
      <div style={{position:"fixed",bottom:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:430,padding:"12px 20px 28px",background:`linear-gradient(to top,${C.bg} 65%,transparent)`,zIndex:100}}>
        <button disabled={disabled()||sending} onClick={next} style={{
          width:"100%",padding:"17px",
          background: disabled()||sending ? C.grayLight : isWA ? "linear-gradient(135deg,#25D366,#128C7E)" : `linear-gradient(135deg,${C.blue},${C.purple})`,
          border:"none",borderRadius:16,
          color: disabled()||sending ? C.gray : "#fff",
          fontSize:15,fontWeight:700,fontFamily:"inherit",
          cursor: disabled()||sending ? "not-allowed":"pointer",
          boxShadow: disabled()||sending ? "none" : isWA ? "0 8px 24px rgba(37,211,102,0.3)" : `0 8px 24px rgba(26,92,255,0.3)`,
          transition:"all 0.2s",
        }}>
          {sending?"Enviando...":
           cur==="intro"  ?"Comenzar diagnóstico →":
           cur==="q1"     ?"Continuar →":
           cur==="inter1" ?"Entiendo, continuar →":
           cur==="q2"     ?"Continuar →":
           cur==="q2b"    ?"Continuar →":
           cur==="inter2" ?"Ver planes disponibles →":
           cur==="q3"     ?"Continuar →":
           cur==="inter3" ?"Ver mi tarifa personalizada →":
           cur==="q4"     ?"Continuar →":
           "Solicitar asesoría por WhatsApp 💬"}
        </button>
      </div>
    </div>
  );
}
